                            const remindDate = new Date(rem.remind_at);
                            const dateStr = remindDate.toLocaleDateString("de-DE", { day: "2-digit", month: "short" });
                            const timeStr = remindDate.toLocaleTimeString("de-DE", { hour: "2-digit", minute: "2-digit" });
